typedef struct { int val, arr, idx; } elem;
int compare(const void *a, const void *b) { return ((elem *)a)->val - ((elem *)b)->val; }
void mergeKArrays(int **arr, int *sizes, int K) {
    elem *heap = (elem *)malloc(K * sizeof(elem));
    for (int i = 0; i < K; i++) {
        heap[i].val = arr[i][0];
        heap[i].arr = i;
        heap[i].idx = 0;
