void mergeKArrays(vector<vector<int>> &arr) {
    priority_queue<elem> heap;
    for (int i = 0; i < arr.size(); i++) {
        if (!arr[i].empty()) {
            heap.push({arr[i][0], i, 0});
        }
    }
    vector<int> result;
    while (!heap.empty()) {
        elem top = heap.top();
        heap.pop();
        result.push_back(top.val);
        if (++top.idx < arr[top.arr].size()) {
            heap.push({arr[top.arr][top.idx], top.arr, top.idx});
        }
    }
    for (int num : result) {
        cout << num << " ";
