import java.util.PriorityQueue;
import java.util.Arrays;
public class Main {
    static class elem implements Comparable<elem> {
        int val, arr, idx;
        elem(int val, int arr, int idx) {
            this.val = val;
            this.arr = arr;
            this.idx = idx;
        }
        @Override
        public int compareTo(elem other) {
            return Integer.compare(val, other.val);
        }
    }
    public static void mergeKArrays(int[][] arr) {
        PriorityQueue<elem> heap = new PriorityQueue<>();
        for (int i = 0; i < arr.length; i++) {
            if (arr[i].length > 0) {
                heap.add(new elem(arr[i][0], i, 0));
            }
        }
        int[] result = new int[arr[0].length + arr[1].length + arr[2].length];
        int idx = 0;
        while (!heap.isEmpty()) {
            elem top = heap.poll();
            result[idx++] = top.val;
            if (++top.idx < arr[top.arr].length) {
                heap.add(new elem(arr[top.arr][top.idx], top.arr, top.idx));
            }
        }
        for (int num : result) {
            System.out.print(num + " ");
        }
        System.out.println();
    }
    public static void main(String[] args) {
        int[][] arr = {{1, 5, 9}, {2, 4, 8}, {3, 6, 7}};
        mergeKArrays(arr);
    }
}

