class elem:
    def __init__(self, val, arr, idx):
        self.val = val
        self.arr = arr
        self.idx = idx

    def __lt__(self, other):
        return self.val < other.val

def mergeKArrays(arr):
    heap = []
    for i, sub_arr in enumerate(arr):
        if sub_arr:
            heapq.heappush(heap, elem(sub_arr[0], i, 0))
    result = []
    while heap:
        top = heapq.heappop(heap)
        result.append(top.val)
        if top.idx + 1 < len(arr[top.arr]):
            heapq.heappush(heap, elem(arr[top.arr][top.idx + 1], top.arr, top.idx + 1))
    print(' '.join(map(str, result)))

